  7→namespace Microsoft.Falcon.LibOnePortal.Utility
  8→{
  9→    using System;
 10→    using System.Net;
 11→    using global::LibOnePortal.Middleware;
 12→    using global::LibOnePortal.Utility;
 13→    using Microsoft.AspNetCore.Authentication.OpenIdConnect;
 14→    using Microsoft.AspNetCore.Authorization;
 15→    using Microsoft.AspNetCore.Builder;
 16→    using Microsoft.AspNetCore.Diagnostics;
 17→    using Microsoft.AspNetCore.Hosting;
 18→    using Microsoft.AspNetCore.Http;
 19→    using Microsoft.AspNetCore.SpaServices.ReactDevelopmentServer;
 20→    using Microsoft.Extensions.DependencyInjection;
 21→    using Microsoft.Extensions.Hosting;
 22→    using Microsoft.Falcon.FalconWebCore;
 23→
 24→    /// <summary>
 25→    /// Provides extension methods for configuring the OnePortal application.
 26→    /// </summary>
 27→    public static class OnePortalApplicationBuilderExtension
 28→    {
 29→        /// <summary>
 30→        /// Configures the application to use OnePortal services and middleware.
 31→        /// It follow the latest template for ASP.NET Core 8.0 and later. Need to use with AddOnePortalFalconServicesSPA.
 32→        /// </summary>
 33→        /// <param name="app">The application builder.</param>
 34→        /// <param name="oneportalConfig">oneportalConfig.</param>
 35→        /// <exception cref="ArgumentNullException">Thrown when <paramref name="app"/> is null.</exception>
 36→        public static void UseOnePortalSPA(this IApplicationBuilder app, OnePortalConfig oneportalConfig)
 37→        {
 38→            if (app == null)
 39→            {
 40→                throw new ArgumentNullException(nameof(app));
 41→            }
 42→
 43→            var envProps = app.ApplicationServices.GetService<IEnvironmentProperties>();
 44→
 45→            app.UseDefaultFiles();
 46→            app.UseStaticFiles();
 47→
 48→            app.UseMiddleware<OnePortalMiddleware>();
 49→            app.UseWebSockets();
 50→
 51→            app.UseRouting();
 52→
 53→            if (envProps!.Environment != EnvironmentEnum.ProductionEnvironment)
 54→            {
 55→                app.UseDeveloperExceptionPage();
 56→            }
 57→
 58→            var cookiePolicyOptions = new CookiePolicyOptions
 59→            {
 60→                Secure = CookieSecurePolicy.Always,
 61→                CheckConsentNeeded = context => true,
 62→            };
 63→            app.UseCookiePolicy(cookiePolicyOptions);
 64→
 65→            app.UseAuthentication();
 66→            app.UseAuthorization();
 67→
 68→            // Configure the HTTP request pipeline.
 69→            app.UseSwagger();
 70→            app.UseSwaggerUI(c =>
 71→            {
 72→                c.OAuthUsePkce();
 73→                c.OAuthClientId(oneportalConfig.AADAuthAppId);
 74→            });
 75→
 76→            app.UseExceptionHandler(
 77→                options =>
 78→                {
 79→                    options.Run(
 80→                        async context =>
 81→                        {
 82→                            context.Response.StatusCode = (int)HttpStatusCode.InternalServerError;
 83→                            var exContext = context.Features.Get<IExceptionHandlerFeature>();
 84→                            if (exContext != null)
 85→                            {
 86→                                if (exContext.Error is UserException)
 87→                                {
 88→                                    context.Response.StatusCode = UserException.UserErrorStatusCode;
 89→                                    await context.Response.WriteAsJsonAsync((exContext.Error as UserException)!.GetUserError()).ConfigureAwait(false);
 90→                                }
 91→                                else
 92→                                {
 93→                                    throw exContext.Error;
 94→                                }
 95→                            }
 96→                        });
 97→                });
 98→
 99→            app.UseEndpoints(endpoints =>
100→            {
101→                var pipeline = endpoints.CreateApplicationBuilder().Build();
102→
103→                endpoints.Map("/swagger", pipeline).RequireAuthorization(new AuthorizeAttribute { AuthenticationSchemes = OpenIdConnectDefaults.AuthenticationScheme });
104→                endpoints.Map("/swagger/index.html", pipeline).RequireAuthorization(new AuthorizeAttribute { AuthenticationSchemes = OpenIdConnectDefaults.AuthenticationScheme });
105→                endpoints.Map("/swagger/v1/swagger.json", pipeline).RequireAuthorization(new AuthorizeAttribute { AuthenticationSchemes = OpenIdConnectDefaults.AuthenticationScheme });
106→                endpoints.Map("/swagger/{documentName}/swagger.json", pipeline).RequireAuthorization(new AuthorizeAttribute { AuthenticationSchemes = OpenIdConnectDefaults.AuthenticationScheme });
107→                endpoints.MapControllers();
108→            });
109→
110→            app.UseHttpsRedirection();
111→        }
112→
113→        /// <summary>
114→        /// Configures the application to use OnePortal services and middleware.
115→        /// </summary>
116→        /// <param name="app">The application builder.</param>
117→        /// <param name="oneportalConfig">oneportalConfig.</param>
118→        /// <exception cref="ArgumentNullException">Thrown when <paramref name="app"/> is null.</exception>
119→        public static void UseOnePortal(this IApplicationBuilder app, OnePortalConfig oneportalConfig)
120→        {
121→            if (app == null)
122→            {
123→                throw new ArgumentNullException(nameof(app));
124→            }
125→
126→            app.UseMiddleware<OnePortalMiddleware>();
127→            app.UseWebSockets();
128→
129→            var envProps = app.ApplicationServices.GetService<IEnvironmentProperties>();
130→
131→            app.UseStaticFiles();
132→            if (!oneportalConfig.EnableProxy)
133→            {
134→                app.UseSpaStaticFiles();
135→            }
136→
137→            app.UseRouting();
138→
139→            if (envProps!.Environment != EnvironmentEnum.ProductionEnvironment)
140→            {
141→                app.UseDeveloperExceptionPage();
142→            }
143→
144→            var cookiePolicyOptions = new CookiePolicyOptions
145→            {
146→                Secure = CookieSecurePolicy.Always,
147→                CheckConsentNeeded = context => true,
148→            };
149→            app.UseCookiePolicy(cookiePolicyOptions);
150→
151→            app.UseAuthentication();
152→            app.UseAuthorization();
153→            if (!oneportalConfig.EnableProxy)
154→            {
155→                app.UseSwagger();
156→                app.UseSwaggerUI(c =>
157→                {
158→                    c.OAuthUsePkce();
159→                    c.OAuthClientId(oneportalConfig.AADAuthAppId);
160→                });
161→            }
162→
163→            app.UseExceptionHandler(
164→                options =>
165→                {
166→                    options.Run(
167→                        async context =>
168→                        {
169→                            context.Response.StatusCode = (int)HttpStatusCode.InternalServerError;
170→                            var exContext = context.Features.Get<IExceptionHandlerFeature>();
171→                            if (exContext != null)
172→                            {
173→                                if (exContext.Error is UserException)
174→                                {
175→                                    context.Response.StatusCode = UserException.UserErrorStatusCode;
176→                                    await context.Response.WriteAsJsonAsync((exContext.Error as UserException)!.GetUserError()).ConfigureAwait(false);
177→                                }
178→                                else
179→                                {
180→                                    throw exContext.Error;
181→                                }
182→                            }
183→                        });
184→                });
185→
186→            app.UseEndpoints(endpoints =>
187→            {
188→                if (!oneportalConfig.EnableProxy)
189→                {
190→                    var pipeline = endpoints.CreateApplicationBuilder().Build();
191→                    endpoints.Map("/swagger", pipeline).RequireAuthorization(new AuthorizeAttribute { AuthenticationSchemes = OpenIdConnectDefaults.AuthenticationScheme });
192→                    endpoints.Map("/swagger/index.html", pipeline).RequireAuthorization(new AuthorizeAttribute { AuthenticationSchemes = OpenIdConnectDefaults.AuthenticationScheme });
193→                    endpoints.Map("/swagger/v1/swagger.json", pipeline).RequireAuthorization(new AuthorizeAttribute { AuthenticationSchemes = OpenIdConnectDefaults.AuthenticationScheme });
194→                    endpoints.Map("/swagger/{documentName}/swagger.json", pipeline).RequireAuthorization(new AuthorizeAttribute { AuthenticationSchemes = OpenIdConnectDefaults.AuthenticationScheme });
195→                    endpoints.MapRazorPages();
196→                }
197→
198→                endpoints.MapControllers();
199→
200→                if (oneportalConfig.EnableProxy)
201→                {
202→                    var handler = new ProxyHandler(oneportalConfig.ProxyDestUrl, oneportalConfig.SkipProxySslValidation);
203→                    endpoints.Map("{*anyURI}", handler.Handle).RequireAuthorization();
204→                }
205→            });
206→
207→            if (!oneportalConfig.EnableProxy)
208→            {
209→                app.UseSpa(spa =>
210→                {
211→                    spa.Options.SourcePath = "ClientApp";
212→                    if (envProps!.Environment == EnvironmentEnum.DevMachine)
213→                    {
214→                        spa.UseReactDevelopmentServer(npmScript: "start");
215→                    }
216→                });
217→            }
218→
219→            app.UseWarmup();
220→        }
221→    }
222→}
