  7→namespace LibOnePortal.Utility
  8→{
  9→    using System;
 10→    using System.Linq;
 11→    using System.Net.Http;
 12→    using System.Net.Http.Headers;
 13→    using System.Net.WebSockets;
 14→    using Microsoft.AspNetCore.Authentication;
 15→    using Microsoft.AspNetCore.Http;
 16→    using Microsoft.Extensions.Primitives;
 17→
 18→    /// <summary>
 19→    /// proxy handler.
 20→    /// </summary>
 21→    internal class ProxyHandler : IDisposable
 22→    {
 23→        private const string WebSocketProtoclHeaderKey = "Sec-WebSocket-Protocol";
 24→
 25→        private const int WebSocketProxyBufferLen = 256;
 26→
 27→        // TODO: debug problem caused by copying "Accept-Encoding"
 28→        private readonly string[] proxyHeadersBlackList = { "Accept-Encoding", "Host" };
 29→
 30→        /// <summary>
 31→        /// The base target URI.
 32→        /// </summary>
 33→        private readonly Uri baseDestUrl;
 34→
 35→        /// <summary>
 36→        /// http client.
 37→        /// </summary>
 38→        private HttpClient httpClient;
 39→
 40→        /// <summary>
 41→        /// Initializes a new instance of the <see cref="ProxyHandler"/> class.
 42→        /// </summary>
 43→        /// <param name="destUrl">dest url.</param>
 44→        /// <param name="skipProxySslValidation">slip ssl validation.</param>
 45→        public ProxyHandler(string destUrl, bool skipProxySslValidation)
 46→        {
 47→            this.baseDestUrl = new Uri(destUrl);
 48→            var handler = new HttpClientHandler();
 49→            if (skipProxySslValidation)
 50→            {
 51→                handler.ClientCertificateOptions = ClientCertificateOption.Manual;
 52→                handler.ServerCertificateCustomValidationCallback =
 53→                    (httpRequestMessage, cert, cetChain, policyErrors) =>
 54→                    {
 55→                        return this.baseDestUrl.Host.Equals(httpRequestMessage?.RequestUri?.Host, StringComparison.OrdinalIgnoreCase);
 56→                    };
 57→            }
 58→
 59→            this.httpClient = new HttpClient(handler);
 60→        }
 61→
 62→        /// <summary>
 63→        /// handle.
 64→        /// </summary>
 65→        /// <param name="ctx">http context.</param>
 66→        /// <returns>none.</returns>
 67→        public async Task Handle(HttpContext ctx)
 68→        {
 69→            if (ctx.WebSockets.IsWebSocketRequest)
 70→            {
 71→                await this.HandleWebSocket(ctx);
 72→            }
 73→            else
 74→            {
 75→                var authToken = await ctx.GetTokenAsync("id_token");
 76→                var proxyReq = this.CloneHttpRequest(ctx.Request, this.baseDestUrl, authToken);
 77→
 78→                var origResp = await this.httpClient.SendAsync(proxyReq);
 79→                await this.CloneHttpResponse(ctx.Response, origResp);
 80→                await ctx.Response.CompleteAsync();
 81→            }
 82→        }
 83→
 84→        /// <inheritdoc/>
 85→        public void Dispose()
 86→        {
 87→            this.httpClient.Dispose();
 88→        }
 89→
 90→        /// <summary>
 91→        /// clones http request.
 92→        /// </summary>
 93→        /// <param name="req">original request.</param>
 94→        /// <param name="hostOverride">replacement base URI.</param>
 95→        /// <param name="bearerToken">bearer token.</param>
 96→        /// <returns>cloned request.</returns>
 97→        private HttpRequestMessage CloneHttpRequest(HttpRequest req, Uri hostOverride, string? bearerToken)
 98→        {
 99→            HttpRequestMessage clone = new HttpRequestMessage(new HttpMethod(req.Method.ToUpper()), hostOverride);
100→            clone.RequestUri = new Uri(this.baseDestUrl, $"{req.Path}{req.QueryString}");
101→            clone.Content = new StreamContent(req.Body);
102→
103→            if (bearerToken != null)
104→            {
105→                clone.Headers.Authorization = new AuthenticationHeaderValue("Bearer", bearerToken);
106→            }
107→
108→            foreach (var hdr in req.Headers.Where(h => !this.proxyHeadersBlackList.Contains(h.Key)))
109→            {
110→                if (hdr.Key.StartsWith("content-", StringComparison.OrdinalIgnoreCase))
111→                {
112→                    clone.Content.Headers.Add(hdr.Key, hdr.Value.ToArray());
113→                }
114→                else
115→                {
116→                    clone.Headers.Add(hdr.Key, hdr.Value.ToArray());
117→                }
118→            }
119→
120→            clone.Headers.Host = hostOverride.Host;
121→            return clone;
122→        }
123→
124→        private async Task CloneHttpResponse(HttpResponse clone, HttpResponseMessage original)
125→        {
126→            string body = await original.Content.ReadAsStringAsync();
127→            foreach (var header in original.Headers.Concat(original.Content.Headers))
128→            {
129→                clone.Headers.Append(header.Key, new StringValues(header.Value.ToArray()));
130→            }
131→
132→            clone.StatusCode = (int)original.StatusCode;
133→            var origBody = await original.Content.ReadAsByteArrayAsync();
134→            if (origBody != null && origBody.Any())
135→            {
136→                await clone.Body.WriteAsync(origBody);
137→            }
138→        }
139→
140→        /// <summary>
141→        /// Handle websocket connection.
142→        /// </summary>
143→        /// <param name="ctx">context.</param>
144→        /// <returns>none.</returns>
145→        private async Task HandleWebSocket(HttpContext ctx)
146→        {
147→            string wsScheme = this.baseDestUrl.Scheme;
148→            if (this.baseDestUrl.Scheme == Uri.UriSchemeHttps)
149→            {
150→                wsScheme = Uri.UriSchemeWss;
151→            }
152→            else if (this.baseDestUrl.Scheme == Uri.UriSchemeHttp)
153→            {
154→                wsScheme = Uri.UriSchemeWs;
155→            }
156→
157→            var uriBuilder = new UriBuilder(this.baseDestUrl)
158→            {
159→                Scheme = wsScheme,
160→                Path = ctx.Request.Path,
161→                Query = ctx.Request.QueryString.Value,
162→            };
163→
164→            var targetUri = uriBuilder.Uri;
165→
166→            var subProtocols = this.ExtractWebSocketProtocols(ctx.Request);
167→
168→            // TODO: add support for multiple subprotocols
169→            using (var clientWebSocket = await ctx.WebSockets.AcceptWebSocketAsync(subProtocols.FirstOrDefault()))
170→            {
171→                using (var serverWebSocket = new ClientWebSocket())
172→                {
173→                    foreach (var p in subProtocols)
174→                    {
175→                        serverWebSocket.Options.AddSubProtocol(p);
176→                    }
177→
178→                    await serverWebSocket.ConnectAsync(targetUri, CancellationToken.None);
179→                    var clientBuffer = new byte[WebSocketProxyBufferLen];
180→                    var serverBuffer = new byte[WebSocketProxyBufferLen];
181→                    var clientToServer = this.ProxyWebSocket(clientWebSocket, serverWebSocket, clientBuffer);
182→                    var serverToClient = this.ProxyWebSocket(serverWebSocket, clientWebSocket, serverBuffer);
183→                    await Task.WhenAll(clientToServer, serverToClient);
184→                }
185→            }
186→        }
187→
188→        /// <summary>
189→        /// Proxy source websocket to destination websocket.
190→        /// </summary>
191→        /// <param name="source">source ws.</param>
192→        /// <param name="destination">dest ws.</param>
193→        /// <param name="buffer">buffer.</param>
194→        /// <returns>none.</returns>
195→        private async Task ProxyWebSocket(WebSocket source, WebSocket destination, byte[] buffer)
196→        {
197→            while (true)
198→            {
199→                var result = await source.ReceiveAsync(new ArraySegment<byte>(buffer), CancellationToken.None);
200→                await destination.SendAsync(new ArraySegment<byte>(buffer, 0, result.Count), result.MessageType, result.EndOfMessage, CancellationToken.None);
201→                if (result.MessageType == WebSocketMessageType.Close)
202→                {
203→                    await destination.CloseAsync(result.CloseStatus!.Value, result.CloseStatusDescription, CancellationToken.None);
204→                    break;
205→                }
206→            }
207→        }
