        var onePortalServiceSPA = Activator.CreateInstance<T>();
        onePortalServiceSPA.ConfigureHostApplicationBuilder(hostBuilder);  // Configure ports/HTTPS
        onePortalServiceSPA.ConfigureServices(hostBuilder.Services);        // DI setup
